<?php session_start(); require 'includes/header.php'; require_login(); if($_SERVER['REQUEST_METHOD']==='POST' && can_manage()){ $pdo->prepare('INSERT INTO suppliers(name,phone,email,address,tin,contact_person) VALUES(?,?,?,?,?,?)')->execute([$_POST['name'],$_POST['phone'],$_POST['email'],$_POST['address'],$_POST['tin'],$_POST['contact_person']]); header('Location:suppliers.php'); exit; } $rows=$pdo->query('SELECT * FROM suppliers ORDER BY name')->fetchAll(); ?><h1>Suppliers</h1><div class="card"><form method="post" class="formgrid"><input name="name" placeholder="Supplier Name" required><input name="phone" placeholder="Phone"><input name="email" placeholder="Email"><input name="tin" placeholder="TIN"><input name="contact_person" placeholder="Contact Person"><textarea name="address" placeholder="Address"></textarea><button>Save Supplier</button></form></div><div class="card"><table><tr><th>Name</th><th>Phone</th><th>Email</th><th>Contact</th></tr><?php foreach($rows as $r): ?><tr><td><?=e($r['name'])?></td><td><?=e($r['phone'])?></td><td><?=e($r['email'])?></td><td><?=e($r['contact_person'])?></td></tr><?php endforeach ?></table></div><?php require 'includes/footer.php'; ?>
